def plot_waveform(name: str, table: list):
    # Generate x values (index positions)
    x = np.arange(len(table))

    # Plot the data
    plt.figure(figsize=(10, 5))
    plt.plot(x, table, linestyle='-', color='b', label=name)
    plt.xlabel('Index')
    plt.ylabel('Value')
    plt.title(name)
    plt.legend()
    plt.grid()
    plt.show()

